def is_valid_move(self, start_pos, end_pos):
    x1, y1 = start_pos
    x2, y2 = end_pos

    if (x1 + y1) % 2 == 0:
        return False

    if abs(x1 - x2) != abs(y1 - y2):
        return False

    piece = self.board[x1][y1]
    if piece is None or piece[0] != self.player_turn:
        return False

    if (x2, y2) in [(x1 + 1, y1 + 1), (x1 - 1, y1 + 1)] and piece == 'w':
        return False
    if (x2, y2) in [(x1 + 1, y1 - 1), (x1 - 1, y1 - 1)] and piece == 'b':
        return False

    if abs(x1 - x2) == 2:
        middle_piece = self.board[(x1 + x2) // 2][(y1 + y2) // 2]
        if middle_piece is None or middle_piece[0] == self.player_turn:
            return False

    return True
```

#### Method: `make_move(start_pos, end_pos)`

```python
def make_move(self, start_pos, end_pos):
    x1, y1 = start_pos
    x2, y2 = end_pos

    if not self.is_valid_move(start_pos, end_pos):
        raise ValueError("Invalid move")

    piece = self.board[x1][y1]
    self.board[x1][y1] = None
    self.board[x2][y2] = piece

    if abs(x1 - x2) == 2:
        middle_piece = (x1 + x2) // 2, (y1 + y2) // 2
        self.board[middle_piece[0]][middle_piece[1]] = None

    if self.player_turn == 'b':
        self.player_turn = 'w'
    else:
        self.player_turn = 'b'
```

