from board import Board

def get_move():
    return input("Enter move (e.g., a1-b2): ")

def main():
    board = Board()
    while not board.is_game_over():
        board.print_board()
        print(f"Player {board.player_turn}'s turn")
        move = get_move()
        # Parse the move and call make_move
        start_pos = (int(move[1]) - 1, ord(move[0]) - ord('a'))
        end_pos = (int(move[4]) - 1, ord(move[3]) - ord('a'))
        board.make_move(start_pos, end_pos)

if __name__ == "__main__":
    main()
```

